import React, { useState, useEffect } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";

const PostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [newComment, setNewComment] = useState("");

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setPost(res.data);

        const commentsRes = await API.get(`/comments/${id}`);
        setComments(commentsRes.data);
      } catch (err) {
        setError("Post not found or error loading post");
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  const handleAddComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim()) return;

    try {
      const res = await API.post(`/comments/${id}`, {
        body: newComment,
      });

      setComments([res.data, ...comments]);
      setNewComment("");
    } catch (err) {
      setError("Failed to add comment");
    }
  };

  if (loading)
    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        Loading post...
      </div>
    );

  if (error)
    return (
      <div style={{ textAlign: "center", padding: "40px", color: "red" }}>
        {error}
        <br />
        <button onClick={() => navigate("/")}>Go Home</button>
      </div>
    );

  if (!post) return <div>No post found</div>;

  const isOwner =
    user &&
    post?.author &&
    user._id === post.author._id;

  return (
    <div style={{ maxWidth: "900px", margin: "40px auto", padding: "20px" }}>

      {/* HEADER BUTTONS */}
      <div style={{ marginBottom: "20px" }}>
        <div style={{ display: "flex", gap: "10px", flexWrap: "wrap" }}>

          <Link
            to="/"
            style={{
              padding: "10px 14px",
              borderRadius: "25px",
              textDecoration: "none",
              fontSize: "14px",
              fontWeight: "bold",
              background: "#f7c6d9",
              color: "rgb(12, 75, 52)",
              border: "1px solid rgb(12, 75, 52)",
            }}
          >
            ⬅ Back Home
          </Link>

          <Link
            to="/create-post"
            style={{
              padding: "10px 14px",
              borderRadius: "25px",
              textDecoration: "none",
              fontSize: "14px",
              fontWeight: "bold",
              background: "#f7c6d9",
              color: "rgb(12, 75, 52)",
              border: "1px solid rgb(12, 75, 52)",
            }}
          >
            ➕ New Post
          </Link>

          {isOwner && (
            <>
              <Link
                to={`/edit-post/${id}`}
                style={{
                  padding: "10px 14px",
                  borderRadius: "25px",
                  textDecoration: "none",
                  fontSize: "14px",
                  fontWeight: "bold",
                  background: "#1a4120",
                  color: "white",
                }}
              >
                ✏️ Edit
              </Link>

              <button
                style={{
                  padding: "10px 14px",
                  borderRadius: "25px",
                  border: "none",
                  background: "#ff4d6d",
                  color: "white",
                  fontWeight: "bold",
                  cursor: "pointer",
                }}
              >
                🗑 Delete
              </button>
            </>
          )}

        </div>
      </div>

      {/* POST CARD */}
      <div
        style={{
          background: "#fff",
          borderRadius: "20px",
          padding: "20px",
          boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
          marginBottom: "30px",
        }}
      >
        <h2>{post.title}</h2>

        {post.image && (
          <img
            src={`http://localhost:5000/uploads/${post.image}`}
            alt="post"
            style={{
              width: "100%",
              borderRadius: "15px",
              margin: "15px 0",
            }}
          />
        )}

        <p style={{ fontSize: "16px", lineHeight: "1.6" }}>
          {post.body}
        </p>

        <small style={{ fontSize: "12px", color: "gray" }}>
          By {post.author?.name} ·{" "}
          {new Date(post.createdAt).toLocaleDateString()}
        </small>
      </div>

      {/* COMMENTS */}
      <div style={{ marginTop: "30px" }}>

        <h3>💬 Comments ({comments.length})</h3>

        {user && (
          <form
            onSubmit={handleAddComment}
            style={{ display: "flex", gap: "10px", marginBottom: "15px" }}
          >
            <input
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
              placeholder="Write a comment..."
              style={{
                flex: 1,
                padding: "10px",
                borderRadius: "20px",
                border: "1px solid rgb(12, 75, 52)",
              }}
            />

            <button
              type="submit"
              style={{
                padding: "10px 16px",
                borderRadius: "20px",
                border: "none",
                background: "rgb(12, 75, 52)",
                color: "white",
                cursor: "pointer",
              }}
            >
              Post
            </button>
          </form>
        )}

        {comments.map((c) => (
          <div
            key={c._id}
            style={{
              background: "#f7c6d9",
              padding: "10px",
              borderRadius: "12px",
              marginBottom: "10px",
            }}
          >
            <strong>{c.author?.name || "User"}</strong>
            <p style={{ margin: 0 }}>{c.body}</p>
          </div>
        ))}

      </div>

    </div>
  );
};

export default PostPage;
